#include <stdio.h>
#include <stdbool.h>
#define MAX 100000

int main() {
    bool prime[MAX + 1];
    for (int i = 0; i <= MAX; i++) prime[i] = true;
    prime[1] = false;
    for (int p = 2; p * p <= MAX; p++) {
        if (prime[p]) {
            for (int i = p * p; i <= MAX; i += p) prime[i] = false;
        }
    }
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        if (prime[N]) printf("yes\n");
        else printf("no\n");
    }
    return 0;
}

