const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const sieveOfEratosthenes = (n) => {
    const prime = new Array(n + 1).fill(true);
    prime[1] = false;
    for (let p = 2; p * p <= n; p++) {
        if (prime[p]) {
            for (let i = p * p; i <= n; i += p) prime[i] = false;
        }
    }
    return prime;
};

const prime = sieveOfEratosthenes(100000);
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    if (prime[N]) console.log('yes');
    else console.log('no');
}
